__global__ void nw_block_kernel_top_left(int *input_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty, int blk)
{
    int b_index_x = blockIdx.x;

    if(b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for(int i = 0; i < BLOCK_SIZE; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for(int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    for(int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for(int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = d_maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for(int i = 0; i < BLOCK_SIZE; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = 
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_block_kernel_bottom_right(int *input_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty, int blk, int max_blk)
{
    int b_index_x = blockIdx.x + blk - 1;

    if(b_index_x >= max_blk) return;

    int b_index_y = max_blk + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for(int i = 0; i < BLOCK_SIZE; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for(int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    for(int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for(int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = d_maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for(int i = 0; i < BLOCK_SIZE; ++i)
    {
        for(int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = 
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int *d_input_itemsets, *d_referrence;
    int transfer_size = max_rows * max_cols;

    cudaMalloc(&d_input_itemsets, transfer_size * sizeof(int));
    cudaMalloc(&d_referrence, transfer_size * sizeof(int));

    cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, transfer_size * sizeof(int), cudaMemcpyHostToDevice);

    int max_blk = (max_cols - 1) / BLOCK_SIZE;

    for(int blk = 1; blk <= max_blk; blk++)
    {
        nw_block_kernel_top_left<<<blk, 1>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for(int blk = 2; blk <= max_blk; blk++)
    {
        int num_blocks = max_blk - blk + 1;
        nw_block_kernel_bottom_right<<<num_blocks, 1>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk, max_blk);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size * sizeof(int), cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> <num_threads>\n", argv[0]);
    fprintf(stderr, "\t<dimension>      - x and y dimensions\n");
    fprintf(stderr, "\t<penalty>        - penalty(positive integer)\n");
    fprintf(stderr, "\t<num_threads>    - no. of threads\n");
    exit(1);
}

int main(int argc, char** argv)
{
    runTest(argc, argv);
    return EXIT_SUCCESS;
}

